  ('disabled-c5fb3965-moex-00071', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '關於行政法院與普通法院就審判權所生爭議之處理，下列敘述何者錯誤？', '["行政法院認其有審判權而為裁判經確定者，其他法院不受該裁判之羈束", "移送訴訟前如有急迫情形，行政法院應依當事人聲請或依職權為必要之 處分", "行政法院認其對訴訟無審判權者，應依職權以裁定將訴訟移送至有審判 權之管轄法院", "當事人對行政法院有無審判權有爭執者，行政法院應就此先為裁定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
