  ('disabled-c5fb3965-moex-00073', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '下列公法上爭議事件，何者屬於行政法院管轄？', '["社會秩序維護法之裁罰事件", "律師懲戒委員會之懲戒決定", "公職人員選舉當選無效之訴訟", "公務人員考績丙等"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00074', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '關於行政訴訟調解規定之敘述，下列何者錯誤？', '["必要時，經行政法院許可者，得就訴訟標的以外之事項，併予調解", "當事人必須就訴訟標的有處分權，始得移付調解", "行政法院得將事件移付調解，毋須經當事人合意", "調解必須無礙公益之維護，始得移付調解"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00075', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '依國家賠償法規定，關於因公共設施所致之國家賠償責任，下列敘述何者 正確？', '["開放水域之自然公物，無國家賠償法之適用", "公共設施，僅限於國家享有所有權之設施", "必須是公共設施在設置或管理上有所欠缺", "因公共設施所侵害之法益，僅限於生命或身體"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00076', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '關於國家賠償，下列敘述何者錯誤？', '["公務員於退休前，因執行職務行使公權力，違法侵害甲之權利，該公務 員雖已退休，甲仍可主張國家賠償", "行政機關編制外之人員，於執行公文送達職務時，駕車撞傷乙，乙可主 張國家賠償", "交通部中央氣象署發布氣象預報違失，致民眾丙財產受有損害，丙可主 張國家賠償", "警員丁駕駛巡邏警車值勤，行經政府疏於修護之道路，致警車翻覆而受 傷，丁不得主張國家賠償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00077', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '行政機關基於公益目的，依土地徵收條例之規定，徵收私人土地以興建國 民小學，原土地所有權人應獲得徵收補償，下列何者為補償的標準？', '["酌量補償", "合理補償", "衡平補償", "回復補償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00078', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '下列文句「」中的成語，何者運用最恰當？', '["他是「一絲不苟」的人，一向粗心大意，所以做事常常出紕漏", "我們專業貼心的居家清潔服務，保證讓您的居室「充棟汗牛」", "他努力克服各種挑戰，最終達成任務，便「志得意滿」的笑了", "您的言論真是「拋磚引玉」，為我將來的研究提供了不少幫助"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00079', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '下列新聞標題，沒有出現贅詞的選項是：', '["冬季流感嚴峻 致死率果然唯恐上升", "樂透有望加碼 或許獎金可能加碼一億", "新春憾事 超商店員遭疑似酒駕嫌疑人撞傷", "消失的年夜飯 未收到預訂年夜飯者高達百人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
